declare const lucide: any;

interface PerformanceTableProps {
    employeeData: EmployeeData;
    onEmployeeClick: (employeeName: string) => void;
    onExport?: () => void;
    isExporting?: boolean;
}

type SortKey = keyof Employee | 'name' | 'percentHT' | 'dtVuot' | 'target';
type SortDirection = 'asc' | 'desc';
type GroupType = 'doanhThu' | 'khaiThac' | 'vuotTroi';

const getTraChamPercentClass = (percentage: number) => {
    if (isNaN(percentage)) return 'text-slate-600 dark:text-slate-300';
    if (percentage >= 45) return 'text-green-500 font-bold';
    if (percentage >= 35) return 'text-amber-500 font-bold';
    return 'text-red-500 font-bold';
};

const getProgressBarColor = (percent: number) => {
    if (percent >= 100) return 'bg-gradient-to-r from-emerald-500 to-teal-400';
    if (percent >= 80) return 'bg-gradient-to-r from-blue-500 to-indigo-400';
    if (percent >= 50) return 'bg-gradient-to-r from-amber-500 to-yellow-400';
    return 'bg-gradient-to-r from-red-500 to-orange-400';
};

const getPercentTextColor = (percent: number) => {
    if (percent >= 100) return 'text-emerald-700 dark:text-emerald-400';
    if (percent >= 80) return 'text-blue-700 dark:text-blue-400';
    if (percent >= 50) return 'text-amber-700 dark:text-amber-400';
    return 'text-red-700 dark:text-red-400';
};

const colorThemes = [
    { name: 'emerald', header: 'bg-emerald-100 dark:bg-emerald-900/50 text-emerald-900 dark:text-emerald-200', row: 'bg-emerald-50 dark:bg-emerald-900/30', border: 'border-emerald-500' },
    { name: 'sky', header: 'bg-sky-100 dark:bg-sky-900/50 text-sky-900 dark:text-sky-200', row: 'bg-sky-50 dark:bg-sky-900/30', border: 'border-sky-500' },
    { name: 'amber', header: 'bg-amber-100 dark:bg-amber-900/50 text-amber-900 dark:text-amber-200', row: 'bg-amber-50 dark:bg-amber-900/30', border: 'border-amber-500' },
    { name: 'rose', header: 'bg-rose-100 dark:bg-rose-900/50 text-rose-900 dark:text-rose-200', row: 'bg-rose-50 dark:bg-rose-900/30', border: 'border-rose-500' },
    { name: 'indigo', header: 'bg-indigo-100 dark:bg-indigo-900/50 text-indigo-900 dark:text-indigo-200', row: 'bg-indigo-50 dark:bg-indigo-900/30', border: 'border-indigo-500' },
    { name: 'teal', header: 'bg-teal-100 dark:bg-teal-900/50 text-teal-900 dark:text-teal-200', row: 'bg-teal-50 dark:bg-teal-900/30', border: 'border-teal-500' },
    { name: 'cyan', header: 'bg-cyan-100 dark:bg-cyan-900/50 text-cyan-900 dark:text-cyan-200', row: 'bg-cyan-50 dark:bg-cyan-900/30', border: 'border-cyan-500' },
    { name: 'fuchsia', header: 'bg-fuchsia-100 dark:bg-fuchsia-900/50 text-fuchsia-900 dark:text-fuchsia-200', row: 'bg-fuchsia-50 dark:bg-fuchsia-900/30', border: 'border-fuchsia-500' },
    { name: 'lime', header: 'bg-lime-100 dark:bg-lime-900/50 text-lime-900 dark:text-lime-200', row: 'bg-lime-50 dark:bg-lime-900/30', border: 'border-lime-500' },
    { name: 'purple', header: 'bg-purple-100 dark:bg-purple-900/50 text-purple-900 dark:text-purple-200', row: 'bg-purple-50 dark:bg-purple-900/30', border: 'border-purple-500' },
];

const RenderSingleTable = ({
    groupType,
    sortConfig,
    onSort,
    tableRef,
    onSingleExport,
    isExporting,
    groupedData,
    outstandingData,
    grandTotal,
    targetPerEmployee,
    fullSellerArrayLength,
    onEmployeeClick,
    isEditingTarget,
    targetInputRef,
    setTargetPerEmployee,
    handleSaveTarget,
    setIsEditingTarget,
    tempTarget,
    setTempTarget,
}: {
    groupType: GroupType;
    sortConfig: { key: SortKey; direction: SortDirection };
    onSort: (key: SortKey) => void;
    tableRef: React.RefObject<HTMLDivElement>;
    onSingleExport: () => void;
    isExporting?: boolean;
    groupedData: { [key: string]: Employee[] };
    outstandingData: { [key: string]: Employee[] };
    grandTotal: any;
    targetPerEmployee: number;
    fullSellerArrayLength: number;
    onEmployeeClick: (name: string) => void;
    isEditingTarget: boolean;
    targetInputRef: React.RefObject<HTMLInputElement>;
    setTargetPerEmployee: (val: number) => void;
    handleSaveTarget: () => void;
    setIsEditingTarget: (val: boolean) => void;
    tempTarget: string;
    setTempTarget: (val: string) => void;
}) => {
    const [copySuccess, setCopySuccess] = useState(false);
    // State to show specific column copy success (stores the key of copied column)
    const [columnCopySuccess, setColumnCopySuccess] = useState<string | null>(null);

    let themeIndex = 0;
    let title = "";
    let icon = "";
    let headers: { label: string, key: SortKey }[] = [];
    let dataToRender: any = groupedData;

    if (groupType === 'doanhThu') {
        themeIndex = 0;
        title = 'HIỆU QUẢ DOANH THU QĐ';
        icon = 'dollar-sign';
        headers = [
            { label: 'Thực', key: 'doanhThuThuc' }, { label: 'DTQĐ', key: 'doanhThuQD' },
            { label: 'HQQĐ', key: 'hieuQuaValue' }, { label: '%T.CHẬM', key: 'dtTraChamPercent_CE_ICT' as any },
            { label: '#YẾU', key: 'weakPointsRevenue' as any }
        ];
    } else if (groupType === 'khaiThac') {
        themeIndex = 1;
        title = 'HIỆU QUẢ KHAI THÁC TRẢ CHẬM/CE+ICT';
        icon = 'recycle';
        headers = [
            { label: 'T.Cận', key: 'slTiepCan' }, { label: 'CE/ICT', key: 'slCE_ICT' as any },
            { label: 'T.CHẬM', key: 'slTraCham_CE_ICT' as any }, { label: '%T.CHẬM', key: 'traChamPercent_CE_ICT' as any },
            { label: '#YẾU', key: 'weakPointsExploitation' as any }
        ];
    } else { // vuotTroi
        themeIndex = 6; // Cyan theme
        const todayDate = new Date().toLocaleDateString('vi-VN');
        title = `MỤC TIÊU VƯỢT TRỘI - ${todayDate}`;
        icon = 'target';
        headers = [
            { label: 'Thực', key: 'doanhThuThuc' },
            { label: 'DTQĐ', key: 'doanhThuQD' },
            { label: 'TAR', key: 'target' as SortKey },
            { label: '%HT', key: 'percentHT' },
            { label: 'HQQĐ', key: 'hieuQuaValue' },
            { label: '%T.CHẬM', key: 'dtTraChamPercent_CE_ICT' as any },
            { label: 'DT VƯỢT', key: 'dtVuot' }
        ];
        dataToRender = outstandingData;
    }

    const tableColorTheme = colorThemes[themeIndex % colorThemes.length];

    const handleCopyBottom40 = (e: React.MouseEvent, key: SortKey, label: string) => {
        e.stopPropagation(); // Prevent sorting

        // Flatten data
        const allEmployees = Object.values(dataToRender).flat() as any[];
        if (allEmployees.length === 0) return;

        // 1. Sort ascending (lowest first)
        const sorted = [...allEmployees].sort((a, b) => {
            const valA = a[key] ?? 0;
            const valB = b[key] ?? 0;
            return valA - valB;
        });

        const totalCount = sorted.length;
        const initialCutoff = Math.ceil(totalCount * 0.4); // 40% count

        // 2. Logic: Take bottom 40%. BUT if the list has many 0s (or lowest value), take ALL of them.
        const valueAtCutoff = sorted[initialCutoff - 1]?.[key] ?? 0;

        let finalSelection = [];

        if (valueAtCutoff <= 0) {
             // If the 40th percentile is 0, we take EVERYONE who is <= 0 (which is just 0)
             finalSelection = sorted.filter(emp => (emp[key] ?? 0) <= 0);
        } else {
             finalSelection = sorted.slice(0, initialCutoff);
        }

        const getId = (n: string) => n.split(/[-–]/)[0].trim();

        let content = `⚠️ CẢNH BÁO: DANH SÁCH ${label.toUpperCase()} THẤP (BOTTOM 40%)\n`;
        content += `Các bạn sau cần tập trung cải thiện chỉ số này ngay:\n`;
        finalSelection.forEach(e => content += `@${getId(e.name)}\n`);

        navigator.clipboard.writeText(content).then(() => {
            setColumnCopySuccess(String(key));
            setTimeout(() => setColumnCopySuccess(null), 2000);
        });
    };

    const renderHeader = (label: string, sortKey: SortKey) => {
        const isTargetHeader = label === 'TAR' && groupType === 'vuotTroi';
        // Allow copy for specific metrics in Vuot Troi table
        const canCopy = groupType === 'vuotTroi' && ['doanhThuThuc', 'doanhThuQD', 'percentHT', 'dtVuot', 'hieuQuaValue', 'dtTraChamPercent_CE_ICT'].includes(String(sortKey));

        // If it's the target header and we are editing, render the input field inside the TH
        if (isTargetHeader && isEditingTarget) {
            return (
                <th key={sortKey} className="px-1 py-1 w-24 align-middle">
                    <input 
                        ref={targetInputRef}
                        type="number" 
                        value={tempTarget} 
                        onChange={(e) => setTempTarget(e.target.value)}
                        onBlur={handleSaveTarget} // Save on blur (click outside)
                        className="w-full px-1 py-1 text-xs text-center border-2 border-indigo-500 rounded bg-white text-slate-900 shadow-sm focus:outline-none"
                        autoFocus
                        onKeyDown={(e) => {
                            if (e.key === 'Enter') handleSaveTarget();
                            if (e.key === 'Escape') setIsEditingTarget(false);
                        }}
                    />
                </th>
            );
        }

        return (
            <th 
                key={sortKey}
                onClick={() => {
                    if (isTargetHeader) {
                        setTempTarget(String(targetPerEmployee)); // Initialize with current value
                        setIsEditingTarget(true);
                    } else {
                        onSort(sortKey);
                    }
                }}
                className={`px-2 py-3 text-xs font-bold uppercase tracking-wider cursor-pointer text-center relative group/header transition-colors hover:bg-black/5 dark:hover:bg-white/5`}
                title={isTargetHeader ? "Nhấn để điều chỉnh Mục tiêu (Target)" : "Nhấn để sắp xếp"}
            >
                <div className="flex items-center justify-center gap-1">
                    {label}
                    {isTargetHeader && <Icon name="edit-3" size={3} className="text-slate-500 dark:text-slate-400" />}
                    {canCopy && (
                        <button
                            onClick={(e) => handleCopyBottom40(e, sortKey, label)}
                            className="p-1 rounded-full hover:bg-red-100 text-slate-400 hover:text-red-600 transition-colors opacity-0 group-hover/header:opacity-100"
                            title="Copy danh sách Bottom 40% (@User)"
                        >
                            <Icon name="copy" size={3} />
                        </button>
                    )}
                </div>
                {columnCopySuccess === String(sortKey) && (
                    <div className="absolute top-0 left-0 w-full h-full bg-green-500 text-white text-[9px] flex items-center justify-center z-10 animate-fade-in">
                        Copied!
                    </div>
                )}
            </th>
        );
    };

    const handleCopyRanking = () => {
        if (groupType !== 'vuotTroi') return;

        // Flatten the dataToRender (grouped by department)
        const allEmployees = Object.values(dataToRender).flat() as any[];

        if (allEmployees.length === 0) return;

        // Sort by %HT descending
        const sorted = [...allEmployees].sort((a, b) => b.percentHT - a.percentHT);

        const top3 = sorted.slice(0, 3);
        const bottomCount = Math.ceil(sorted.length * 0.3); // "BOTTOM 30%"
        const bottom30 = sorted.slice(-bottomCount);

        const getId = (n: string) => {
            const parts = n.split(/[-–]/);
            return parts[0].trim();
        };

        let content = `🌟 VINH DANH TOP 3 CHIẾN BINH XUẤT SẮC - DẪN ĐẦU TỶ LỆ HOÀN THÀNH MỤC TIÊU 🌟\nTuyệt vời! Các bạn là động lực bứt phá cho cả tập thể:\n`;
        top3.forEach(e => content += `@${getId(e.name)}\n`);

        content += `\n⚠️ CẢNH BÁO ĐỎ: NHÓM CUỐI BẢNG ĐANG KÉO LÙI KẾT QUẢ CHUNG CỦA CẢ SHOP ⚠️\nĐề nghị các nhân sự sau nghiêm túc xem lại hiệu suất và tốc độ làm việc. Đừng để sự chậm trễ của cá nhân ảnh hưởng đến công sức của tập thể:\n`;
        bottom30.forEach(e => content += `@${getId(e.name)}\n`);

        navigator.clipboard.writeText(content).then(() => {
            setCopySuccess(true);
            setTimeout(() => setCopySuccess(false), 2000);
        }).catch(err => {
            console.error('Failed to copy: ', err);
            alert("Không thể copy, vui lòng thử lại.");
        });
    };

    const showDeptHeaders = Object.keys(dataToRender).length > 1 || (Object.keys(dataToRender).length === 1 && Object.keys(dataToRender)[0] !== 'Không Phân Ca');
    const medals = ['🥇', '🥈', '🥉'];

    return (
        <div ref={tableRef} className={`border rounded-lg ${tableColorTheme.border} overflow-hidden h-fit`}>
            <div 
                className={`p-4 ${tableColorTheme.header} border-b-2 ${tableColorTheme.border} relative text-center transition-all duration-300 ${groupType === 'vuotTroi' ? 'cursor-pointer hover:brightness-95 group/title' : ''}`}
                onClick={handleCopyRanking}
                title={groupType === 'vuotTroi' ? 'Nhấn để copy danh sách TOP/BOTTOM theo %HT' : ''}
            >
                {copySuccess && groupType === 'vuotTroi' && (
                    <div className="absolute inset-0 bg-green-500/90 dark:bg-green-600/90 flex items-center justify-center z-30 animate-in fade-in zoom-in duration-200 text-white font-bold text-lg gap-2">
                        <Icon name="check-circle" size={6} className="text-white" />
                        <span>Đã sao chép bảng vinh danh!</span>
                    </div>
                )}

                <h3 className="text-lg font-bold flex items-center justify-center gap-2">
                    <Icon name={icon} size={5} /> 
                    <span>{title}</span>
                    {groupType === 'vuotTroi' && (
                        <span className="opacity-0 group-hover/title:opacity-100 transition-opacity text-xs bg-black/20 text-white px-2 py-0.5 rounded-full ml-2 flex items-center gap-1">
                            <Icon name="copy" size={3} /> Copy
                        </span>
                    )}
                </h3>

                <div className="hide-on-export absolute top-1/2 right-4 -translate-y-1/2 z-20">
                    <button onClick={(e) => { e.stopPropagation(); onSingleExport(); }} disabled={isExporting} title="Xuất Ảnh Bảng Này" className="p-1.5 rounded-full text-slate-600 dark:text-slate-300 hover:bg-black/10 transition-colors">
                            <Icon name="camera" size={4} />
                    </button>
                </div>
            </div>
            <div className="overflow-x-auto table-container">
                <table className="min-w-full compact-export-table">
                    <thead className={tableColorTheme.header}>
                        <tr className="divide-x divide-current/20">
                            <th onClick={() => onSort('name')} className="px-4 py-3 text-left text-xs font-bold uppercase tracking-wider cursor-pointer bg-inherit align-middle w-40">
                                Nhân Viên
                            </th>
                            {headers.map(h => renderHeader(h.label, h.key))}
                        </tr>
                    </thead>
                    <tbody>
                        {Object.entries(dataToRender).map(([dept, employees]: [string, any[]]) => {
                            const sortedEmployees = [...employees].sort((a, b) => {
                                const valA = a[sortConfig.key]; const valB = b[sortConfig.key];
                                if (typeof valA === 'number' && typeof valB === 'number') {
                                    const result = sortConfig.direction === 'asc' ? valA - valB : valB - valA;
                                    if (result !== 0) return result;
                                }
                                return a.name.localeCompare(b.name);
                            });

                            return (
                            <React.Fragment key={dept}>
                                {showDeptHeaders && (
                                    <tr className={`${tableColorTheme.row} border-t-2 ${tableColorTheme.border}`}>
                                        <td colSpan={1 + headers.length} className="px-4 py-2 text-sm font-bold">
                                            <div className="flex items-center gap-2"><Icon name="users-round" size={4} /><span>{dept}</span></div>
                                        </td>
                                    </tr>
                                )}
                                {sortedEmployees.map((employee, index) => {
                                    const rankIndex = index;
                                    const medal = rankIndex < 3 ? medals[rankIndex] : null;
                                    let rankDisplay;
                                    if (medal) {
                                        rankDisplay = <div className="w-8 text-2xl font-bold text-center">{medal}</div>;
                                    } else {
                                        rankDisplay = <div className="w-8 text-sm text-slate-500 dark:text-slate-400 font-semibold text-center">#{rankIndex + 1}</div>
                                    }

                                    const rowClass = index % 2 === 0 ? 'bg-white dark:bg-slate-800/50' : tableColorTheme.row;

                                    return (
                                    <tr key={employee.name} className={`${rowClass} hover:bg-slate-100 dark:hover:bg-slate-700/50 transition-colors divide-x divide-slate-200 dark:divide-slate-700`}>
                                        <td className="px-4 py-2 text-sm font-medium text-slate-800 dark:text-slate-200 whitespace-nowrap">
                                            <div className="flex items-center gap-2">
                                                {rankDisplay}
                                                <span onClick={() => onEmployeeClick(employee.name)} className="cursor-pointer hover:underline truncate" title={employee.name}>
                                                    {abbreviateName(employee.name)}
                                                </span>
                                            </div>
                                        </td>
                                        {headers.map(h => (
                                            <td key={h.key} className={`px-2 py-2 text-center text-sm ${h.key === 'percentHT' ? 'bg-indigo-50 dark:bg-indigo-900/20 border-x border-indigo-100 dark:border-indigo-800' : 'text-slate-600 dark:text-slate-300'}`}>
                                                {/* Common Columns */}
                                                { h.key === 'doanhThuThuc' && formatCurrency(employee.doanhThuThuc) }
                                                { h.key === 'doanhThuQD' && <span className="font-bold text-green-700 dark:text-green-500">{formatCurrency(employee.doanhThuQD)}</span> }
                                                { h.key === 'hieuQuaValue' && <span className={employee.hieuQuaValue < 35 ? 'text-red-500 font-bold' : 'text-green-500 font-bold'}>{employee.hieuQuaValue.toFixed(0)}%</span> }

                                                {/* Doanh Thu Specific */}
                                                { h.key === 'dtTraChamPercent_CE_ICT' && <span className={getTraChamPercentClass(employee.dtTraChamPercent_CE_ICT)}>{employee.dtTraChamPercent_CE_ICT.toFixed(0)}%</span> }
                                                { h.key === 'weakPointsRevenue' && <span className={`font-bold ${employee.weakPointsRevenue > 0 ? 'text-red-600 dark:text-red-400' : ''}`}>{employee.weakPointsRevenue > 0 ? employee.weakPointsRevenue : '-'}</span> }

                                                {/* Khai Thac Specific */}
                                                { h.key === 'slTiepCan' && formatQuantity(employee.slTiepCan) }
                                                { h.key === 'slCE_ICT' && formatQuantity(employee.slCE_ICT) }
                                                { h.key === 'slTraCham_CE_ICT' && formatQuantity(employee.slTraCham_CE_ICT) }
                                                { h.key === 'traChamPercent_CE_ICT' && <span className={getTraChamPercentClass(employee.traChamPercent_CE_ICT)}>{employee.traChamPercent_CE_ICT.toFixed(0)}%</span> }
                                                { h.key === 'weakPointsExploitation' && <span className={`font-bold ${employee.weakPointsExploitation > 0 ? 'text-red-600 dark:text-red-400' : ''}`}>{employee.weakPointsExploitation > 0 ? employee.weakPointsExploitation : '-'}</span> }

                                                {/* Vuot Troi Specific */}
                                                { h.key === 'target' && formatCurrency(employee.target, 0).replace('Tr', '') }
                                                { h.key === 'percentHT' && (
                                                    <div className="flex flex-col items-center justify-center gap-1">
                                                        <span className={`text-xs font-black ${getPercentTextColor(employee.percentHT)}`}>
                                                            {employee.percentHT.toFixed(0)}%
                                                        </span>
                                                        <div className="w-full bg-slate-200 dark:bg-slate-700 rounded-full h-2 relative overflow-hidden">
                                                            <div 
                                                                className={`h-full rounded-full transition-all duration-500 ${getProgressBarColor(employee.percentHT)}`} 
                                                                style={{ width: `${Math.min(employee.percentHT, 100)}%` }}
                                                            ></div>
                                                        </div>
                                                    </div>
                                                )}
                                                { h.key === 'dtVuot' && <span className={`font-bold ${employee.dtVuot > 0 ? 'text-green-600 dark:text-green-400' : 'text-slate-400'}`}>{employee.dtVuot > 0 ? `+${formatCurrency(employee.dtVuot)}` : '-'}</span> }
                                            </td>
                                        ))}
                                    </tr>
                                )})}
                            </React.Fragment>
                        )})}
                    </tbody>
                    <tfoot className="font-extrabold uppercase">
                            <tr className={tableColorTheme.header}>
                            <td className={`px-4 py-3 text-sm border-t-2 ${tableColorTheme.border}`}>Tổng cộng</td>
                            {headers.map(h => (
                                <td key={h.key} className={`px-2 py-3 text-sm text-center border-t-2 ${tableColorTheme.border}`}>
                                    { h.key === 'doanhThuThuc' && formatCurrency(grandTotal.doanhThuThuc) }
                                    { h.key === 'doanhThuQD' && <span className="font-bold text-green-700 dark:text-green-500">{formatCurrency(grandTotal.doanhThuQD)}</span> }
                                    { h.key === 'hieuQuaValue' && <span className={grandTotal.hieuQuaValue < 35 ? 'text-red-600' : 'text-green-600'}>{grandTotal.hieuQuaValue.toFixed(0)}%</span> }
                                    { h.key === 'dtTraChamPercent_CE_ICT' && <span className={getTraChamPercentClass(grandTotal.dtTraChamPercent_CE_ICT)}>{grandTotal.dtTraChamPercent_CE_ICT.toFixed(0)}%</span> }
                                    { h.key === 'weakPointsRevenue' && formatQuantity(grandTotal.weakPointsRevenue) }
                                    { h.key === 'slTiepCan' && formatQuantity(grandTotal.slTiepCan) }
                                    { h.key === 'slCE_ICT' && formatQuantity(grandTotal.slCE_ICT) }
                                    { h.key === 'slTraCham_CE_ICT' && formatQuantity(grandTotal.slTraCham_CE_ICT) }
                                    { h.key === 'traChamPercent_CE_ICT' && <span className={getTraChamPercentClass(grandTotal.traChamPercent_CE_ICT)}>{grandTotal.traChamPercent_CE_ICT.toFixed(0)}%</span> }
                                    { h.key === 'weakPointsExploitation' && formatQuantity(grandTotal.weakPointsExploitation) }

                                    {/* Totals for Vuot Troi (Simplification: Average/Sum depending on metric) */}
                                    { h.key === 'target' && formatCurrency(targetPerEmployee * fullSellerArrayLength) }
                                    { h.key === 'percentHT' && '-' }
                                    { h.key === 'dtVuot' && <span className="text-green-700 dark:text-green-400">{formatCurrency(grandTotal.doanhThuQD - (targetPerEmployee * fullSellerArrayLength))}</span> }
                                </td>
                            ))}
                        </tr>
                    </tfoot>
                </table>
            </div>
        </div>
    );
};

const PerformanceTable = forwardRef<HTMLDivElement, PerformanceTableProps>(({ employeeData, onEmployeeClick, onExport, isExporting }, ref) => {
    const { handleExport } = useDashboardContext();
    const { fullSellerArray } = employeeData;
    const [sortConfigDoanhThu, setSortConfigDoanhThu] = useState<{ key: SortKey; direction: SortDirection }>({ key: 'hieuQuaValue', direction: 'desc' });
    const [sortConfigKhaiThac, setSortConfigKhaiThac] = useState<{ key: SortKey; direction: SortDirection }>({ key: 'traChamPercent_CE_ICT', direction: 'desc' });
    const [sortConfigVuotTroi, setSortConfigVuotTroi] = useState<{ key: SortKey; direction: SortDirection }>({ key: 'dtVuot', direction: 'desc' });

    const [targetPerEmployee, setTargetPerEmployee] = useState<number>(0);
    const [isEditingTarget, setIsEditingTarget] = useState(false);
    const targetInputRef = useRef<HTMLInputElement>(null);
    const [tempTarget, setTempTarget] = useState<string>(''); // For non-blocking input

    const [analysis, setAnalysis] = useState<string | null>(null);
    const [isAnalysisLoading, setIsAnalysisLoading] = useState(false);

    const doanhThuTableRef = useRef<HTMLDivElement>(null);
    const khaiThacTableRef = useRef<HTMLDivElement>(null);
    const vuotTroiTableRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (ref && typeof ref !== 'function' && ref.current && typeof lucide !== 'undefined') {
            const timer = setTimeout(() => {
                lucide.createIcons({ root: ref.current });
            }, 150);
            return () => clearTimeout(timer);
        }
    }, [employeeData, ref]);

    useEffect(() => {
        getDailyTarget().then(val => {
            const t = val || 50000000;
            setTargetPerEmployee(t);
            setTempTarget(String(t));
        });
    }, []);

    const handleSaveTarget = () => {
        setIsEditingTarget(false);
        const val = Number(tempTarget);
        if (!isNaN(val)) {
            setTargetPerEmployee(val);
            saveDailyTarget(val);
        }
    };

    const handleAiAnalysis = async () => {
        setIsAnalysisLoading(true);
        setAnalysis(null);
        try {
            const result = await getPerformanceTableAnalysis(employeeData);
            setAnalysis(result);
        } catch (error) {
            console.error("Lỗi khi phân tích bảng hiệu suất:", error);
            setAnalysis("Đã xảy ra lỗi khi phân tích. Vui lòng thử lại.");
        } finally { setIsAnalysisLoading(false); }
    };

    const { groupedData, groupTotals, grandTotal, outstandingData } = useMemo(() => {
        // Logic cũ cho bảng Hiệu suất và Khai thác (chỉ lấy người có doanh thu)
        const employeesWithSales = fullSellerArray.filter(s => s.doanhThuThuc > 0);

        const calculateTotals = (items: Employee[]) => {
            const initialTotals = {
                doanhThuThuc: 0, doanhThuQD: 0, slTiepCan: 0, slTraCham: 0, doanhThuTraCham: 0,
                slCE_ICT: 0, slTraCham_CE_ICT: 0, doanhThu_CE_ICT: 0, doanhThuTraCham_CE_ICT: 0,
                weakPointsRevenue: 0, weakPointsExploitation: 0,
            };
            if (items.length === 0) return { ...initialTotals, hieuQuaValue: 0, traChamPercent: 0, traChamPercent_CE_ICT: 0, dtTraChamPercent_CE_ICT: 0 };

            const t = items.reduce((acc, d) => {
                for (const key of Object.keys(initialTotals) as (keyof typeof initialTotals)[]) {
                    const value = d[key as keyof Employee];
                    if (typeof value === 'number') {
                        acc[key] += value;
                    }
                }
                return acc;
            }, { ...initialTotals });

            return { ...t, 
                hieuQuaValue: t.doanhThuThuc > 0 ? ((t.doanhThuQD - t.doanhThuThuc) / t.doanhThuThuc) * 100 : 0,
                traChamPercent: t.doanhThuThuc > 0 ? (t.doanhThuTraCham / t.doanhThuThuc) * 100 : 0,
                traChamPercent_CE_ICT: t.slCE_ICT > 0 ? (t.slTraCham_CE_ICT / t.slCE_ICT) * 100 : 0,
                dtTraChamPercent_CE_ICT: t.doanhThu_CE_ICT > 0 ? (t.doanhThuTraCham_CE_ICT / t.doanhThu_CE_ICT) * 100 : 0,
            };
        };

        const grouped = employeesWithSales.reduce((acc, employee) => {
            const dept = employee.department || 'Không Phân Ca';
            if (!acc[dept]) acc[dept] = [];
            acc[dept].push(employee);
            return acc;
        }, {} as { [key: string]: Employee[] });

        const groupTotals: { [key: string]: any } = {};
        for (const dept in grouped) { groupTotals[dept] = calculateTotals(grouped[dept]); }
        const grandTotal = calculateTotals(employeesWithSales);

        const sortedGroupKeys = Object.keys(grouped).sort((a, b) => a.localeCompare(b));
        const finalGroupedData: { [key: string]: Employee[] } = {};
        sortedGroupKeys.forEach(key => { finalGroupedData[key] = grouped[key]; });

        // Logic MỚI cho bảng Vượt trội (Lấy tất cả nhân viên trong file phân ca/dữ liệu)
        const outstandingEmployees = fullSellerArray.map(emp => ({
            ...emp,
            target: targetPerEmployee,
            percentHT: targetPerEmployee > 0 ? (emp.doanhThuQD / targetPerEmployee) * 100 : 0,
            dtVuot: emp.doanhThuQD - targetPerEmployee
        }));

        const groupedOutstanding = outstandingEmployees.reduce((acc, employee) => {
            const dept = employee.department || 'Không Phân Ca';
            if (!acc[dept]) acc[dept] = [];
            acc[dept].push(employee);
            return acc;
        }, {} as { [key: string]: typeof outstandingEmployees });

        const finalOutstandingData: { [key: string]: typeof outstandingEmployees } = {};
        Object.keys(groupedOutstanding).sort().forEach(key => {
            finalOutstandingData[key] = groupedOutstanding[key];
        });

        return { groupedData: finalGroupedData, groupTotals, grandTotal, outstandingData: finalOutstandingData };
    }, [fullSellerArray, targetPerEmployee]);

    const handleSort = (groupType: GroupType, key: SortKey) => {
        let setSort: React.Dispatch<React.SetStateAction<{ key: SortKey; direction: SortDirection }>>;
        if (groupType === 'doanhThu') setSort = setSortConfigDoanhThu;
        else if (groupType === 'khaiThac') setSort = setSortConfigKhaiThac;
        else setSort = setSortConfigVuotTroi;

        setSort(prev => ({ key, direction: prev.key === key && prev.direction === 'desc' ? 'asc' : 'desc' }));
    };

    const handleSingleExport = async (groupType: GroupType) => {
        let refToUse: React.RefObject<HTMLDivElement>;
        let fileName = "";
        if (groupType === 'doanhThu') { refToUse = doanhThuTableRef; fileName = "hieu-qua-doanh-thu-qd.png"; }
        else if (groupType === 'khaiThac') { refToUse = khaiThacTableRef; fileName = "hieu-qua-khai-thac.png"; }
        else { refToUse = vuotTroiTableRef; fileName = "muc-tieu-vuot-troi.png"; }

        if (refToUse.current) {
            await handleExport(refToUse.current, fileName, { isCompactTable: true });
        }
    };

    const handleBatchExportClick = async () => {
        if (vuotTroiTableRef.current) {
            await handleExport(vuotTroiTableRef.current, 'muc-tieu-vuot-troi.png', { isCompactTable: true });
            await new Promise(res => setTimeout(res, 300));
        }
        if (doanhThuTableRef.current) {
            await handleExport(doanhThuTableRef.current, 'hieu-qua-doanh-thu-qd.png', { isCompactTable: true });
            await new Promise(res => setTimeout(res, 300));
        }
        if (khaiThacTableRef.current) {
            await handleExport(khaiThacTableRef.current, 'hieu-qua-khai-thac-tra-cham.png', { isCompactTable: true });
        }
    };

    return (
        <div ref={ref}>
             <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">Bảng Hiệu Suất Toàn Diện</h3>
                 <div className="flex items-center gap-2 hide-on-export">
                    <button onClick={handleAiAnalysis} disabled={isAnalysisLoading} className="p-1.5 rounded-full text-slate-500 hover:bg-slate-200 dark:text-slate-400 dark:hover:bg-slate-700 transition-colors" title="Nhận xét tổng quan bằng AI">
                        {isAnalysisLoading ? <Icon name="loader-2" size={4} className="animate-spin" /> : <Icon name="sparkles" size={4} />}
                    </button>
                    {onExport && (
                        <button onClick={handleBatchExportClick} disabled={isExporting} title="Xuất Hàng Loạt Ảnh" className="p-1.5 rounded-full text-slate-500 hover:bg-slate-200 dark:text-slate-400 dark:hover:bg-slate-700 transition-colors">
                            {isExporting ? <Icon name="loader-2" size={4} className="animate-spin" /> : <Icon name="images" size={4} />}
                        </button>
                    )}
                </div>
            </div>

            <div className="flex flex-col gap-6">
                <RenderSingleTable
                    groupType="vuotTroi"
                    sortConfig={sortConfigVuotTroi}
                    onSort={(key) => handleSort('vuotTroi', key)}
                    tableRef={vuotTroiTableRef}
                    onSingleExport={() => handleSingleExport('vuotTroi')}
                    isExporting={isExporting}
                    groupedData={groupedData}
                    outstandingData={outstandingData}
                    grandTotal={grandTotal}
                    targetPerEmployee={targetPerEmployee}
                    fullSellerArrayLength={fullSellerArray.length}
                    onEmployeeClick={onEmployeeClick}
                    isEditingTarget={isEditingTarget}
                    targetInputRef={targetInputRef}
                    setTargetPerEmployee={setTargetPerEmployee}
                    handleSaveTarget={handleSaveTarget}
                    setIsEditingTarget={setIsEditingTarget}
                    tempTarget={tempTarget}
                    setTempTarget={setTempTarget}
                />

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <RenderSingleTable
                        groupType="doanhThu"
                        sortConfig={sortConfigDoanhThu}
                        onSort={(key) => handleSort('doanhThu', key)}
                        tableRef={doanhThuTableRef}
                        onSingleExport={() => handleSingleExport('doanhThu')}
                        isExporting={isExporting}
                        groupedData={groupedData}
                        outstandingData={outstandingData}
                        grandTotal={grandTotal}
                        targetPerEmployee={targetPerEmployee}
                        fullSellerArrayLength={fullSellerArray.length}
                        onEmployeeClick={onEmployeeClick}
                        isEditingTarget={isEditingTarget}
                        targetInputRef={targetInputRef}
                        setTargetPerEmployee={setTargetPerEmployee}
                        handleSaveTarget={handleSaveTarget}
                        setIsEditingTarget={setIsEditingTarget}
                        tempTarget={tempTarget}
                        setTempTarget={setTempTarget}
                    />
                    <RenderSingleTable
                        groupType="khaiThac"
                        sortConfig={sortConfigKhaiThac}
                        onSort={(key) => handleSort('khaiThac', key)}
                        tableRef={khaiThacTableRef}
                        onSingleExport={() => handleSingleExport('khaiThac')}
                        isExporting={isExporting}
                        groupedData={groupedData}
                        outstandingData={outstandingData}
                        grandTotal={grandTotal}
                        targetPerEmployee={targetPerEmployee}
                        fullSellerArrayLength={fullSellerArray.length}
                        onEmployeeClick={onEmployeeClick}
                        isEditingTarget={isEditingTarget}
                        targetInputRef={targetInputRef}
                        setTargetPerEmployee={setTargetPerEmployee}
                        handleSaveTarget={handleSaveTarget}
                        setIsEditingTarget={setIsEditingTarget}
