// Inline Editor Component
const KpiTargetEditor: React.FC<{ 
    value: string; 
    onChange: (val: string) => void; 
    onFinish: () => void; 
    onCancel: () => void;
    className?: string;
}> = ({ value, onChange, onFinish, onCancel, className = "" }) => {
    const inputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (inputRef.current) {
            inputRef.current.focus();
            inputRef.current.select();
        }
    }, []);

    return (
        <div className={`flex items-center gap-1 ${className}`} onClick={(e) => e.stopPropagation()}>
            <input
                ref={inputRef}
                type="number"
                min="0"
                max="100"
                value={value}
                onChange={(e) => onChange(e.target.value)}
                onBlur={onFinish}
                onKeyDown={(e) => {
                    if (e.key === 'Enter') onFinish();
                    if (e.key === 'Escape') onCancel();
                    e.stopPropagation(); 
                }}
                className="w-12 px-1 py-0.5 text-center text-sm font-bold text-slate-900 bg-slate-100 rounded-md focus:ring-2 focus:ring-blue-500 outline-none"
            />
            <span className="text-xs font-bold text-slate-500">%</span>
        </div>
    );
};

const KpiCards: React.FC<KpiCardsProps> = ({ onUnshippedClick }) => {
    const { processedData } = useDashboardContext();
    const kpis = processedData?.kpis;
    const [targets, setTargets] = useState({ hieuQua: 40, traGop: 45 });

    // State for inline editing
    const [editingState, setEditingState] = useState<{ field: 'hieuQua' | 'traGop' | null, value: string }>({ field: null, value: '' });

    useEffect(() => {
        getKpiTargets().then(saved => {
            if (saved) {
                setTargets(saved);
            }
        });
    }, []);

    const startEditing = (e: React.MouseEvent, field: 'hieuQua' | 'traGop') => {
        e.preventDefault();
        e.stopPropagation();
        setEditingState({ field, value: (field === 'hieuQua' ? targets.hieuQua : targets.traGop).toString() });
    };

    const handleEditChange = (val: string) => {
        setEditingState(prev => ({ ...prev, value: val }));
    };

    const submitEditing = () => {
        if (!editingState.field) return;
        const newVal = parseFloat(editingState.value);
        if (!isNaN(newVal) && newVal >= 0 && newVal <= 100) {
            const newTargets = { ...targets, [editingState.field]: newVal };
            setTargets(newTargets);
            saveKpiTargets(newTargets).catch(console.error);
        }
        setEditingState({ field: null, value: '' });
    };

    const cancelEditing = () => {
        setEditingState({ field: null, value: '' });
    };

    if (!kpis) {
        return null;
    }

    // Logic colors
    const hieuQuaValue = kpis.hieuQuaQD * 100;
    const isHieuQuaGood = hieuQuaValue >= targets.hieuQua;
    const isTraGopGood = kpis.traGopPercent >= targets.traGop;

    return (
        <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-6 mb-10 kpi-grid-for-export">

            {/* CARD 1: DOANH THU QUY ĐỔI */}
            <KpiCard 
                icon="wallet-cards" 
                iconColor="blue" 
                title="Doanh Thu Quy Đổi"
                footer={
                    <div className="flex justify-between items-center text-xs font-medium text-slate-500 dark:text-slate-400">
                        <div className="flex flex-col">
                            <span className="text-[10px] uppercase tracking-wider text-slate-400">Thực tế</span>
                            <span className="text-slate-700 dark:text-slate-200 font-bold text-sm">{formatCurrency(kpis.totalRevenue)}</span>
                        </div>
                        <div className="flex flex-col items-end">
                            <span className="text-[10px] uppercase tracking-wider text-slate-400">Thu hộ</span>
                            <span className="text-slate-700 dark:text-slate-200 font-bold text-sm">{formatQuantity(kpis.soLuongThuHo)}</span>
                        </div>
                    </div>
                }
            >
                <div className="text-4xl font-semibold tracking-tighter text-slate-900 dark:text-white">
                    {formatCurrency(kpis.doanhThuQD)}
                </div>
            </KpiCard>

            {/* CARD 2: HIỆU QUẢ QUY ĐỔI */}
            <KpiCard 
                icon="trending-up" 
                iconColor="teal" 
                title="Hiệu Quả Quy Đổi"
                onClick={(e) => startEditing(e, 'hieuQua')}
                footer={
                    <div className="flex justify-between items-center text-xs">
                        <span className="text-slate-400 font-medium">Mục tiêu:</span>
                        {editingState.field === 'hieuQua' ? (
                            <KpiTargetEditor 
                                value={editingState.value} onChange={handleEditChange} onFinish={submitEditing} onCancel={cancelEditing} 
                            />
                        ) : (
                            <span className="font-bold text-slate-700 dark:text-slate-200 bg-slate-100 dark:bg-white/10 px-2 py-1 rounded-md">{targets.hieuQua}%</span>
                        )}
                    </div>
                }
            >
                <div className={`text-4xl font-semibold tracking-tighter ${isHieuQuaGood ? 'text-emerald-600 dark:text-emerald-400' : 'text-amber-500'}`}>
                    {hieuQuaValue.toFixed(1)}%
                </div>
                <div className="w-full bg-slate-100 dark:bg-slate-800 rounded-full h-1.5 mt-2 overflow-hidden">
                    <div className={`h-full rounded-full ${isHieuQuaGood ? 'bg-emerald-500' : 'bg-amber-500'}`} style={{ width: `${Math.min(hieuQuaValue, 100)}%` }}></div>
                </div>
            </KpiCard>

            {/* CARD 3: TỶ LỆ TRẢ GÓP */}
            <KpiCard 
                icon="receipt" 
                iconColor="pink" 
                title="Tỷ Lệ Trả Góp"
                onClick={(e) => startEditing(e, 'traGop')}
                footer={
                    <div className="flex justify-between items-center text-xs">
                        <span className="text-slate-400 font-medium">Mục tiêu:</span>
                        {editingState.field === 'traGop' ? (
                            <KpiTargetEditor 
                                value={editingState.value} onChange={handleEditChange} onFinish={submitEditing} onCancel={cancelEditing} 
                            />
                        ) : (
                            <span className="font-bold text-slate-700 dark:text-slate-200 bg-slate-100 dark:bg-white/10 px-2 py-1 rounded-md">{targets.traGop}%</span>
                        )}
                    </div>
                }
            >
                <div className={`text-4xl font-semibold tracking-tighter ${isTraGopGood ? 'text-pink-600 dark:text-pink-400' : 'text-amber-500'}`}>
                    {kpis.traGopPercent.toFixed(1)}%
                </div>
                <div className="flex justify-between items-center mt-2 text-xs font-medium text-slate-500 dark:text-slate-400">
                    <span>{formatQuantity(kpis.traGopCount)} đơn</span>
                    <span>{formatCurrency(kpis.traGopValue)}</span>
                </div>
            </KpiCard>

            {/* CARD 4: DOANH THU CHỜ XUẤT */}
            <KpiCard 
                icon="archive-restore" 
                iconColor="red" 
                title="DT Chờ Xuất" 
                onClick={onUnshippedClick}
                footer={
                    <div className="flex items-center gap-2 text-xs font-medium text-red-600 dark:text-red-400 group">
                        <span className="group-hover:underline">Xem chi tiết đơn hàng</span>
                        <Icon name="arrow-right" size={3} />
                    </div>
                }
            >
                <div className="text-4xl font-semibold tracking-tighter text-slate-900 dark:text-white">
                    {formatCurrency(kpis.doanhThuQDChoXuat)}
                </div>
                <div className="text-xs font-medium text-slate-500 dark:text-slate-400 mt-1">
                    Thực tế: <span className="text-slate-700 dark:text-slate-200 font-bold">{formatCurrency(kpis.doanhThuThucChoXuat)}</span>
                </div>
            </KpiCard>
        </div>
    );
};

export default KpiCards;

import React, { useState, useEffect, useRef } from 'react';
import { formatCurrency, formatQuantity } from '../../utils/dataUtils';
import { Icon } from '../common/Icon';
import { useDashboardContext } from '../../contexts/DashboardContext';
import { saveKpiTargets, getKpiTargets } from '../../services/dbService';

interface KpiCardsProps {
    onUnshippedClick: () => void;
}

// Compact Horizontal Card
const KpiCard: React.FC<{
    icon: string;
    iconColor: string;
    title: string;
    onClick?: () => void;
    children: React.ReactNode;
    trendLabel?: string;
    trendValue?: string;
}> = ({ icon, iconColor, title, onClick, children, trendLabel, trendValue }) => {
    const isClickable = !!onClick;

    const colorMap: Record<string, string> = {
        blue: 'bg-blue-50 text-blue-600 dark:bg-blue-500/20 dark:text-blue-400',
        teal: 'bg-emerald-50 text-emerald-600 dark:bg-emerald-500/20 dark:text-emerald-400',
        pink: 'bg-pink-50 text-pink-600 dark:bg-pink-500/20 dark:text-pink-400',
        red:  'bg-red-50 text-red-600 dark:bg-red-500/20 dark:text-red-400',
    };

    const iconClass = colorMap[iconColor] || colorMap['blue'];

    return (
        <div
            onClick={onClick}
            className={`relative h-full bg-white dark:bg-[#1c1c1e] rounded-[20px] p-4 shadow-sm border border-slate-100 dark:border-white/5 transition-all duration-300 flex items-center justify-between ${isClickable ? 'cursor-pointer hover:-translate-y-0.5 hover:shadow-md' : ''}`}
        >
            <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${iconClass} shrink-0`}>
                    <Icon name={icon} size={5} />
                </div>
                <div>
                    <h3 className="text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-0.5">{title}</h3>
                    <div className="flex flex-col">
                        {children}
                    </div>
                </div>
            </div>

            {(trendLabel || trendValue) && (
                <div className="text-right pl-4 border-l border-slate-100 dark:border-white/5 shrink-0">
                    <p className="text-[10px] text-slate-400 font-medium">{trendLabel}</p>
                    <p className="text-xs font-bold text-slate-700 dark:text-slate-300 mt-0.5">{trendValue}</p>
                </div>
            )}
        </div>
    );
};

// Inline Editor Component
const KpiTargetEditor: React.FC<{ 
    value: string; 
    onChange: (val: string) => void; 
    onFinish: () => void; 
    onCancel: () => void;
}> = ({ value, onChange, onFinish, onCancel }) => {
    const inputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (inputRef.current) {
            inputRef.current.focus();
            inputRef.current.select();
        }
    }, []);

    return (
        <div className="flex items-center gap-1" onClick={(e) => e.stopPropagation()}>
            <input
                ref={inputRef}
                type="number"
                min="0"
                max="100"
                value={value}
                onChange={(e) => onChange(e.target.value)}
                onBlur={onFinish}
                onKeyDown={(e) => {
                    if (e.key === 'Enter') onFinish();
                    if (e.key === 'Escape') onCancel();
                    e.stopPropagation(); 
                }}
                className="w-10 px-1 py-0.5 text-center text-xs font-bold text-slate-900 bg-slate-100 rounded focus:ring-2 focus:ring-blue-500 outline-none"
            />
            <span className="text-[10px] font-bold text-slate-500">%</span>
        </div>
    );
};

const KpiCards: React.FC<KpiCardsProps> = ({ onUnshippedClick }) => {
    const { processedData } = useDashboardContext();
    const kpis = processedData?.kpis;
    const [targets, setTargets] = useState({ hieuQua: 40, traGop: 45 });

    const [editingState, setEditingState] = useState<{ field: 'hieuQua' | 'traGop' | null, value: string }>({ field: null, value: '' });

    useEffect(() => {
        getKpiTargets().then(saved => {
            if (saved) {
                setTargets(saved);
            }
        });
    }, []);

    const startEditing = (e: React.MouseEvent, field: 'hieuQua' | 'traGop') => {
        e.preventDefault();
        e.stopPropagation();
        setEditingState({ field, value: (field === 'hieuQua' ? targets.hieuQua : targets.traGop).toString() });
    };

    const handleEditChange = (val: string) => {
        setEditingState(prev => ({ ...prev, value: val }));
    };

    const submitEditing = () => {
        if (!editingState.field) return;
        const newVal = parseFloat(editingState.value);
        if (!isNaN(newVal) && newVal >= 0 && newVal <= 100) {
            const newTargets = { ...targets, [editingState.field]: newVal };
            setTargets(newTargets);
            saveKpiTargets(newTargets).catch(console.error);
        }
        setEditingState({ field: null, value: '' });
    };

    const cancelEditing = () => {
        setEditingState({ field: null, value: '' });
    };

    if (!kpis) {
        return null;
    }

    const hieuQuaValue = kpis.hieuQuaQD * 100;
    const isHieuQuaGood = hieuQuaValue >= targets.hieuQua;
    const isTraGopGood = kpis.traGopPercent >= targets.traGop;

    return (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8 kpi-grid-for-export">

            {/* CARD 1: DOANH THU QUY ĐỔI */}
            <KpiCard 
                icon="wallet-cards" 
                iconColor="blue" 
                title="Doanh Thu QĐ"
                trendLabel="Thực tế"
                trendValue={formatCurrency(kpis.totalRevenue)}
            >
                <div className="text-2xl font-bold text-slate-900 dark:text-white leading-none">
                    {formatCurrency(kpis.doanhThuQD)}
                </div>
            </KpiCard>

            {/* CARD 2: HIỆU QUẢ QUY ĐỔI */}
            <KpiCard 
                icon="trending-up" 
                iconColor="teal" 
                title="Hiệu Quả QĐ"
                onClick={(e) => startEditing(e, 'hieuQua')}
                trendLabel="Mục tiêu"
                trendValue={editingState.field === 'hieuQua' ? '' : `${targets.hieuQua}%`}
            >
                {editingState.field === 'hieuQua' ? (
                    <KpiTargetEditor value={editingState.value} onChange={handleEditChange} onFinish={submitEditing} onCancel={cancelEditing} />
                ) : (
                    <div className={`text-2xl font-bold leading-none ${isHieuQuaGood ? 'text-emerald-600 dark:text-emerald-400' : 'text-amber-500'}`}>
                        {hieuQuaValue.toFixed(1)}%
                    </div>
                )}
            </KpiCard>

            {/* CARD 3: TỶ LỆ TRẢ GÓP */}
            <KpiCard 
                icon="receipt" 
                iconColor="pink" 
                title="Tỷ Lệ Trả Góp"
                onClick={(e) => startEditing(e, 'traGop')}
                trendLabel="Mục tiêu"
                trendValue={editingState.field === 'traGop' ? '' : `${targets.traGop}%`}
            >
                {editingState.field === 'traGop' ? (
                    <KpiTargetEditor value={editingState.value} onChange={handleEditChange} onFinish={submitEditing} onCancel={cancelEditing} />
                ) : (
                    <div className={`text-2xl font-bold leading-none ${isTraGopGood ? 'text-pink-600 dark:text-pink-400' : 'text-amber-500'}`}>
                        {kpis.traGopPercent.toFixed(1)}%
                    </div>
                )}
            </KpiCard>

            {/* CARD 4: DOANH THU CHỜ XUẤT */}
            <KpiCard 
                icon="archive-restore" 
                iconColor="red" 
                title="DT Chờ Xuất" 
                onClick={onUnshippedClick}
                trendLabel="Thực tế"
                trendValue={formatCurrency(kpis.doanhThuThucChoXuat)}
            >
                <div className="text-2xl font-bold text-slate-900 dark:text-white leading-none">
                    {formatCurrency(kpis.doanhThuQDChoXuat)}
                </div>
            </KpiCard>
        </div>
    );
};

export default KpiCards;

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { formatCurrency, formatQuantity } from '../../utils/dataUtils';
import { Icon } from '../common/Icon';
import { exportElementAsImage } from '../../services/uiService';
import { useDashboardContext } from '../../contexts/DashboardContext';
import { useIndustryGridLogic } from '../../hooks/useIndustryGridLogic';
import MultiSelectDropdown from '../common/MultiSelectDropdown';

declare const lucide: any;
declare const google: any;

interface IndustryGridProps {}

const IndustryGrid: React.FC<IndustryGridProps> = () => {
    const { processedData, productConfig } = useDashboardContext();
    const industryData = processedData?.industryData ?? [];
    const filteredValidSalesData = processedData?.filteredValidSalesData ?? [];

    const cardRef = useRef<HTMLDivElement>(null);
    const pieChartRef = useRef<HTMLDivElement>(null);
    const barChartRef = useRef<HTMLDivElement>(null);
    const isInitialFilterSet = useRef(false);

    const [isExporting, setIsExporting] = useState(false);
    const [activeTab, setActiveTab] = useState<'card' | 'chart'>('card');

    // Use Custom Hook to handle logic
    const {
        drilldownPath,
        setDrilldownPath,
        currentView,
        allSubgroups,
        selectedChartSubgroups,
        setSelectedChartSubgroups,
        manufacturerDataForChart,
        getTitle
    } = useIndustryGridLogic({ industryData, filteredValidSalesData, productConfig });

    // --- Effects & Handlers ---

    useEffect(() => {
        if (!isInitialFilterSet.current && allSubgroups.includes('Smartphone')) {
            setSelectedChartSubgroups(['Smartphone']);
            isInitialFilterSet.current = true;
        }
    }, [allSubgroups, setSelectedChartSubgroups]);

    useEffect(() => {
        if (lucide) lucide.createIcons();
    }, [currentView.data, activeTab]);

    const drawCharts = useCallback(() => {
        if (!(window as any).google?.visualization) return;
        const isDark = document.documentElement.classList.contains('dark');
        const textColor = isDark ? '#f1f5f9' : '#0f172a';

        // Draw Pie Chart
        if (pieChartRef.current && industryData.length > 0) {
            let pieChartData = [...industryData];
            if (industryData.length > 10) {
                const top10 = industryData.slice(0, 10);
                const otherSlice = industryData.slice(10).reduce((acc, item) => {
                    acc.revenue += item.revenue;
                    acc.quantity += item.quantity;
                    return acc;
                }, { revenue: 0, quantity: 0 });
                pieChartData = [...top10, { name: 'Ngành hàng khác', ...otherSlice }];
            }

            const pieData = new (window as any).google.visualization.DataTable();
            pieData.addColumn('string', 'Ngành hàng');
            pieData.addColumn('number', 'Doanh thu');
            pieData.addColumn({ type: 'string', role: 'tooltip', p: { html: true } });

            pieData.addRows(pieChartData.map(item => {
                const legendLabel = `${item.name}: ${formatCurrency(item.revenue)} (${formatQuantity(item.quantity)} SP)`;
                const tooltip = `
                    <div class="p-2 shadow-lg rounded-md bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 text-sm font-sans">
                        <div class="font-bold text-slate-800 dark:text-slate-100 mb-1">${item.name}</div>
                        <div class="text-slate-600 dark:text-slate-300">Doanh thu: <span class="font-bold text-indigo-600 dark:text-indigo-400">${formatCurrency(item.revenue)}</span></div>
                        <div class="text-slate-600 dark:text-slate-300">Số lượng: <span class="font-bold text-indigo-600 dark:text-indigo-400">${formatQuantity(item.quantity)} SP</span></div>
                    </div>`;
                return [legendLabel, item.revenue, tooltip];
            }));

            const pieOptions = {
                title: 'Top 10 Tỷ Trọng Doanh Thu',
                pieHole: 0.4,
                backgroundColor: 'transparent',
                colors: isDark 
                    ? ['#60a5fa', '#4ade80', '#facc15', '#f87171', '#a78bfa', '#22d3ee', '#fb923c', '#f472b6', '#34d399', '#93c5fd']
                    : ['#3b82f6', '#22c55e', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4', '#f97316', '#ec4899', '#10b981', '#60a5fa'],
                legend: { 
                    position: 'right', 
                    alignment: 'center',
                    textStyle: { color: textColor, fontSize: 12 },
                    maxLines: 1
                },
                titleTextStyle: { color: textColor, fontSize: 16, bold: true },
                chartArea: { left: 10, top: 40, width: '95%', height: '85%' },
                tooltip: { isHtml: true }
            };
            const pieChart = new (window as any).google.visualization.PieChart(pieChartRef.current);
            pieChart.draw(pieData, pieOptions);
        }

        // Draw Bar Chart
        if (barChartRef.current && manufacturerDataForChart.length > 0) {
            const barChartColors = isDark 
                ? ['#a78bfa', '#7dd3fc', '#6ee7b7', '#fde047', '#f9a8d4', '#fda4af', '#fca5a5', '#d8b4fe', '#bfdbfe', '#a7f3d0', '#fef08a', '#fbcfe8', '#fed7aa', '#bae6fd', '#bbf7d0']
                : ['#818cf8', '#38bdf8', '#34d399', '#facc15', '#f472b6', '#fb7185', '#f87171', '#c084fc', '#93c5fd', '#6ee7b7', '#fde047', '#f9a8d4', '#fdba74', '#7dd3fc', '#86efac'];

            const barData = new (window as any).google.visualization.DataTable();
            barData.addColumn('string', 'Nhà sản xuất');
            barData.addColumn('number', 'Doanh thu');
            barData.addColumn({ type: 'string', role: 'style' });
            barData.addColumn({ type: 'string', role: 'annotation' });
            barData.addColumn({ type: 'string', role: 'tooltip', p: { html: true } });

            const top15Manufacturers = manufacturerDataForChart.slice(0, 15);
            top15Manufacturers.forEach((item, index) => {
                const color = barChartColors[index % barChartColors.length];
                const annotation = `${formatCurrency(item.revenue)} | ${formatQuantity(item.quantity)} SP`;
                const tooltip = `
                    <div class="p-2 shadow-lg rounded-md bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 text-sm font-sans">
                        <div class="font-bold text-slate-800 dark:text-slate-100 mb-1">${item.name}</div>
                        <div class="text-slate-600 dark:text-slate-300">Doanh thu: <span class="font-bold text-indigo-600 dark:text-indigo-400">${formatCurrency(item.revenue)}</span></div>
                        <div class="text-slate-600 dark:text-slate-300">Số lượng: <span class="font-bold text-indigo-600 dark:text-indigo-400">${formatQuantity(item.quantity)} SP</span></div>
                    </div>`;
                barData.addRow([item.name, item.revenue, `color: ${color}`, annotation, tooltip]);
            });

            let barChartTitle = 'Top 15 Nhà Sản Xuất (Tất cả)';
            if (selectedChartSubgroups.length === 1) {
                barChartTitle = `Top 15 Nhà Sản Xuất - ${selectedChartSubgroups[0]}`;
            } else if (selectedChartSubgroups.length > 1) {
                barChartTitle = `Top 15 Nhà Sản Xuất - ${selectedChartSubgroups.length} nhóm con`;
            }

            const barOptions = {
                title: barChartTitle,
                backgroundColor: 'transparent',
                legend: { position: 'none' },
                titleTextStyle: { color: textColor, fontSize: 16, bold: true },
                chartArea: { left: 120, top: 40, width: '70%', height: '80%' },
                hAxis: { textStyle: { color: textColor }, gridlines: { color: isDark ? '#334155' : '#e2e8f0' } },
                vAxis: { textStyle: { color: textColor } },
                animation: { startup: true, duration: 1000, easing: 'out' },
                tooltip: { isHtml: true },
                annotations: {
                    alwaysOutside: true,
                    textStyle: { fontSize: 10, color: textColor, auraColor: 'none' }
                }
            };
            const barChart = new (window as any).google.visualization.BarChart(barChartRef.current);
            barChart.draw(barData, barOptions);
        }
    }, [industryData, manufacturerDataForChart, selectedChartSubgroups]);

    useEffect(() => {
        let observer: ResizeObserver;
        const chartCardElement = cardRef.current;

        const drawAndObserve = () => {
             if ((window as any).google?.visualization) {
                drawCharts();
            } else {
                (window as any).google.charts.load('current', { 'packages': ['corechart'] });
                (window as any).google.charts.setOnLoadCallback(drawCharts);
            }

            if (chartCardElement) {
                observer = new ResizeObserver(() => {
                    setTimeout(() => drawCharts(), 150);
                });
                observer.observe(chartCardElement);
            }
        };

        if (activeTab === 'chart') {
            drawAndObserve();
        }

        return () => {
            if (observer && chartCardElement) observer.unobserve(chartCardElement);
        };
    }, [activeTab, drawCharts]);

    const handleExport = async () => {
        if (cardRef.current) {
            setIsExporting(true);
            await exportElementAsImage(cardRef.current, 'ty-trong-nganh-hang.png', {
                elementsToHide: ['.hide-on-export'],
            });
            setIsExporting(false);
        }
    };

    const handleCardClick = (itemName: string) => {
        if (drilldownPath.length < 2) {
            setDrilldownPath(prev => [...prev, itemName]);
        }
    };

    const handleBreadcrumbClick = (index: number) => {
        setDrilldownPath(prev => prev.slice(0, index));
    };

    return (
        <div className="chart-card p-6 bg-white dark:bg-slate-900" ref={cardRef}>
            <div className="flex justify-between items-start mb-4">
                <div>
                     <h2 className="text-lg font-bold text-slate-800 dark:text-slate-100">{getTitle(activeTab)}</h2>
                      {activeTab === 'card' && (
                        <div className="flex items-center text-sm font-medium text-slate-500 dark:text-slate-400 mt-1 hide-on-export">
                           <button onClick={() => handleBreadcrumbClick(0)} className="hover:text-indigo-600 dark:hover:text-indigo-400">All</button>
                           {drilldownPath.map((item, index) => (
                               <div key={index} className="flex items-center">
                                   <Icon name="chevron-right" size={4} className="mx-1" />
                                   <button onClick={() => handleBreadcrumbClick(index + 1)} className="hover:text-indigo-600 dark:hover:text-indigo-400 truncate max-w-[150px]">{item}</button>
                               </div>
                           ))}
                       </div>
                      )}
                </div>
                 <div className="flex items-center gap-2 hide-on-export">
                    {activeTab === 'chart' && (
                        <div className="flex items-center gap-2 w-64">
                             <MultiSelectDropdown 
                               options={allSubgroups}
                               selected={selectedChartSubgroups}
                               onChange={setSelectedChartSubgroups}
                               label="nhóm con"
                            />
                        </div>
                    )}
                    <div className="inline-flex rounded-lg shadow-sm p-1 bg-slate-100/50 dark:bg-slate-900/50">
                        <button onClick={() => setActiveTab('card')} className={`py-1.5 px-4 text-sm font-semibold rounded-md transition-colors ${activeTab === 'card' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-white shadow' : 'text-slate-600 dark:text-slate-300 hover:bg-slate-200/60 dark:hover:bg-slate-700'}`}>Thẻ</button>
                        <button onClick={() => setActiveTab('chart')} className={`py-1.5 px-4 text-sm font-semibold rounded-md transition-colors ${activeTab === 'chart' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-white shadow' : 'text-slate-600 dark:text-slate-300 hover:bg-slate-200/60 dark:hover:bg-slate-700'}`}>Biểu đồ</button>
                    </div>
                    <button onClick={handleExport} disabled={isExporting} title="Xuất Ảnh" className="p-2 text-slate-500 dark:text-slate-400 rounded-md hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors">
                        {isExporting ? <Icon name="loader-2" className="animate-spin" /> : <Icon name="camera" />}
                    </button>
                 </div>
            </div>
            {activeTab === 'card' ? (
                currentView.data.length === 0 ? (
                    <p className="text-slate-500 dark:text-slate-400 text-center py-8">Không có dữ liệu để hiển thị.</p>
                ) : (
                    <div className="grid gap-3 grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 industry-cards-grid">
                        {currentView.data.map(({ name, revenue, quantity, icon, color }) => {
                            const percentage = currentView.totalRevenue > 0 ? (revenue / currentView.totalRevenue * 100) : 0;
                            const isDrillable = drilldownPath.length < 2;
                            return (
                                <div
                                    key={name}
                                    onClick={isDrillable ? () => handleCardClick(name) : undefined}
                                    className={`group relative flex flex-col justify-between h-32 p-4 bg-white dark:bg-[#1c1c1e] border border-slate-200 dark:border-white/5 rounded-xl shadow-sm hover:shadow-md transition-all duration-300 hover:-translate-y-1 ${isDrillable ? 'cursor-pointer' : 'cursor-default'}`}
                                >
                                    {/* Icon and Percent */}
                                    <div className="flex justify-between items-start">
                                        <div className={`w-10 h-10 rounded-lg flex items-center justify-center bg-${color}-50 text-${color}-600 dark:bg-${color}-500/10 dark:text-${color}-400 transition-colors group-hover:bg-${color}-100 dark:group-hover:bg-${color}-500/20`}>
                                            <Icon name={icon} size={5} />
                                        </div>
                                        <span className="text-[10px] font-bold px-2 py-1 rounded-md bg-slate-100 dark:bg-white/10 text-slate-500">
                                            {percentage.toFixed(1)}%
                                        </span>
                                    </div>

                                    {/* Main Info */}
                                    <div className="mt-2">
                                        <div className="text-[11px] font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400 truncate mb-0.5" title={name}>{name}</div>
                                        <div className="text-lg font-bold text-slate-900 dark:text-white tracking-tight leading-none">{formatCurrency(revenue)}</div>
                                        <div className="text-[10px] text-slate-400 mt-1 font-medium">{formatQuantity(quantity)} SP</div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )
            ) : (
                <div className="flex flex-col lg:flex-row items-stretch gap-4">
                    <div className="lg:w-[45%]" ref={pieChartRef} style={{ minHeight: '450px' }}></div>
                    <div className="lg:w-[55%]" ref={barChartRef} style={{ minHeight: '450px' }}></div>
                </div>
            )}
        </div>
    );
};

export default IndustryGrid;

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { formatCurrency, formatQuantity } from '../../utils/dataUtils';
import { Icon } from '../common/Icon';
import { exportElementAsImage } from '../../services/uiService';
import { useDashboardContext } from '../../contexts/DashboardContext';
import { useIndustryGridLogic } from '../../hooks/useIndustryGridLogic';
import MultiSelectDropdown from '../common/MultiSelectDropdown';

declare const lucide: any;
declare const google: any;

interface IndustryGridProps {}

const IndustryGrid: React.FC<IndustryGridProps> = () => {
    const { processedData, productConfig } = useDashboardContext();
    const industryData = processedData?.industryData ?? [];
    const filteredValidSalesData = processedData?.filteredValidSalesData ?? [];

    const cardRef = useRef<HTMLDivElement>(null);
    const pieChartRef = useRef<HTMLDivElement>(null);
    const barChartRef = useRef<HTMLDivElement>(null);
    const isInitialFilterSet = useRef(false);

    const [isExporting, setIsExporting] = useState(false);
    const [activeTab, setActiveTab] = useState<'card' | 'chart'>('card');

    // Use Custom Hook to handle logic
    const {
        drilldownPath,
        setDrilldownPath,
        currentView,
        allSubgroups,
        selectedChartSubgroups,
        setSelectedChartSubgroups,
        manufacturerDataForChart,
        getTitle
    } = useIndustryGridLogic({ industryData, filteredValidSalesData, productConfig });

    // --- Effects & Handlers ---

    useEffect(() => {
        if (!isInitialFilterSet.current && allSubgroups.includes('Smartphone')) {
            setSelectedChartSubgroups(['Smartphone']);
            isInitialFilterSet.current = true;
        }
    }, [allSubgroups, setSelectedChartSubgroups]);

    useEffect(() => {
        if (lucide) lucide.createIcons();
    }, [currentView.data, activeTab]);

    const drawCharts = useCallback(() => {
        if (!(window as any).google?.visualization) return;
        const isDark = document.documentElement.classList.contains('dark');
        const textColor = isDark ? '#f1f5f9' : '#0f172a';

        // Draw Pie Chart
        if (pieChartRef.current && industryData.length > 0) {
            let pieChartData = [...industryData];
            if (industryData.length > 10) {
                const top10 = industryData.slice(0, 10);
                const otherSlice = industryData.slice(10).reduce((acc, item) => {
                    acc.revenue += item.revenue;
                    acc.quantity += item.quantity;
                    return acc;
                }, { revenue: 0, quantity: 0 });
                pieChartData = [...top10, { name: 'Ngành hàng khác', ...otherSlice }];
            }

            const pieData = new (window as any).google.visualization.DataTable();
            pieData.addColumn('string', 'Ngành hàng');
            pieData.addColumn('number', 'Doanh thu');
            pieData.addColumn({ type: 'string', role: 'tooltip', p: { html: true } });

            pieData.addRows(pieChartData.map(item => {
                const legendLabel = `${item.name}: ${formatCurrency(item.revenue)} (${formatQuantity(item.quantity)} SP)`;
                const tooltip = `
                    <div class="p-2 shadow-lg rounded-md bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 text-sm font-sans">
                        <div class="font-bold text-slate-800 dark:text-slate-100 mb-1">${item.name}</div>
                        <div class="text-slate-600 dark:text-slate-300">Doanh thu: <span class="font-bold text-indigo-600 dark:text-indigo-400">${formatCurrency(item.revenue)}</span></div>
                        <div class="text-slate-600 dark:text-slate-300">Số lượng: <span class="font-bold text-indigo-600 dark:text-indigo-400">${formatQuantity(item.quantity)} SP</span></div>
                    </div>`;
                return [legendLabel, item.revenue, tooltip];
            }));

            const pieOptions = {
                title: 'Top 10 Tỷ Trọng Doanh Thu',
                pieHole: 0.4,
                backgroundColor: 'transparent',
                colors: isDark 
                    ? ['#60a5fa', '#4ade80', '#facc15', '#f87171', '#a78bfa', '#22d3ee', '#fb923c', '#f472b6', '#34d399', '#93c5fd']
                    : ['#3b82f6', '#22c55e', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4', '#f97316', '#ec4899', '#10b981', '#60a5fa'],
                legend: { 
                    position: 'right', 
                    alignment: 'center',
                    textStyle: { color: textColor, fontSize: 12 },
                    maxLines: 1
                },
                titleTextStyle: { color: textColor, fontSize: 16, bold: true },
                chartArea: { left: 10, top: 40, width: '95%', height: '85%' },
                tooltip: { isHtml: true }
            };
            const pieChart = new (window as any).google.visualization.PieChart(pieChartRef.current);
            pieChart.draw(pieData, pieOptions);
        }

        // Draw Bar Chart
        if (barChartRef.current && manufacturerDataForChart.length > 0) {
            const barChartColors = isDark 
                ? ['#a78bfa', '#7dd3fc', '#6ee7b7', '#fde047', '#f9a8d4', '#fda4af', '#fca5a5', '#d8b4fe', '#bfdbfe', '#a7f3d0', '#fef08a', '#fbcfe8', '#fed7aa', '#bae6fd', '#bbf7d0']
                : ['#818cf8', '#38bdf8', '#34d399', '#facc15', '#f472b6', '#fb7185', '#f87171', '#c084fc', '#93c5fd', '#6ee7b7', '#fde047', '#f9a8d4', '#fdba74', '#7dd3fc', '#86efac'];

            const barData = new (window as any).google.visualization.DataTable();
            barData.addColumn('string', 'Nhà sản xuất');
            barData.addColumn('number', 'Doanh thu');
            barData.addColumn({ type: 'string', role: 'style' });
            barData.addColumn({ type: 'string', role: 'annotation' });
            barData.addColumn({ type: 'string', role: 'tooltip', p: { html: true } });

            const top15Manufacturers = manufacturerDataForChart.slice(0, 15);
            top15Manufacturers.forEach((item, index) => {
                const color = barChartColors[index % barChartColors.length];
                const annotation = `${formatCurrency(item.revenue)} | ${formatQuantity(item.quantity)} SP`;
                const tooltip = `
                    <div class="p-2 shadow-lg rounded-md bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 text-sm font-sans">
                        <div class="font-bold text-slate-800 dark:text-slate-100 mb-1">${item.name}</div>
                        <div class="text-slate-600 dark:text-slate-300">Doanh thu: <span class="font-bold text-indigo-600 dark:text-indigo-400">${formatCurrency(item.revenue)}</span></div>
                        <div class="text-slate-600 dark:text-slate-300">Số lượng: <span class="font-bold text-indigo-600 dark:text-indigo-400">${formatQuantity(item.quantity)} SP</span></div>
                    </div>`;
                barData.addRow([item.name, item.revenue, `color: ${color}`, annotation, tooltip]);
            });

            let barChartTitle = 'Top 15 Nhà Sản Xuất (Tất cả)';
            if (selectedChartSubgroups.length === 1) {
                barChartTitle = `Top 15 Nhà Sản Xuất - ${selectedChartSubgroups[0]}`;
            } else if (selectedChartSubgroups.length > 1) {
                barChartTitle = `Top 15 Nhà Sản Xuất - ${selectedChartSubgroups.length} nhóm con`;
            }

            const barOptions = {
                title: barChartTitle,
                backgroundColor: 'transparent',
                legend: { position: 'none' },
                titleTextStyle: { color: textColor, fontSize: 16, bold: true },
                chartArea: { left: 120, top: 40, width: '70%', height: '80%' },
                hAxis: { textStyle: { color: textColor }, gridlines: { color: isDark ? '#334155' : '#e2e8f0' } },
                vAxis: { textStyle: { color: textColor } },
                animation: { startup: true, duration: 1000, easing: 'out' },
                tooltip: { isHtml: true },
                annotations: {
                    alwaysOutside: true,
                    textStyle: { fontSize: 10, color: textColor, auraColor: 'none' }
                }
            };
            const barChart = new (window as any).google.visualization.BarChart(barChartRef.current);
            barChart.draw(barData, barOptions);
        }
    }, [industryData, manufacturerDataForChart, selectedChartSubgroups]);

    useEffect(() => {
        let observer: ResizeObserver;
        const chartCardElement = cardRef.current;

        const drawAndObserve = () => {
             if ((window as any).google?.visualization) {
                drawCharts();
            } else {
                (window as any).google.charts.load('current', { 'packages': ['corechart'] });
                (window as any).google.charts.setOnLoadCallback(drawCharts);
            }

            if (chartCardElement) {
                observer = new ResizeObserver(() => {
                    setTimeout(() => drawCharts(), 150);
                });
                observer.observe(chartCardElement);
            }
        };

        if (activeTab === 'chart') {
            drawAndObserve();
        }

        return () => {
            if (observer && chartCardElement) observer.unobserve(chartCardElement);
        };
    }, [activeTab, drawCharts]);

    const handleExport = async () => {
        if (cardRef.current) {
            setIsExporting(true);
            await exportElementAsImage(cardRef.current, 'ty-trong-nganh-hang.png', {
                elementsToHide: ['.hide-on-export'],
            });
            setIsExporting(false);
        }
    };

    const handleCardClick = (itemName: string) => {
        if (drilldownPath.length < 2) {
            setDrilldownPath(prev => [...prev, itemName]);
        }
    };

    const handleBreadcrumbClick = (index: number) => {
        setDrilldownPath(prev => prev.slice(0, index));
    };

    return (
        <div className="chart-card p-6 bg-white dark:bg-slate-900" ref={cardRef}>
            <div className="flex justify-between items-start mb-4">
                <div>
                     <h2 className="text-lg font-bold text-slate-800 dark:text-slate-100">{getTitle(activeTab)}</h2>
                      {activeTab === 'card' && (
                        <div className="flex items-center text-sm font-medium text-slate-500 dark:text-slate-400 mt-1 hide-on-export">
                           <button onClick={() => handleBreadcrumbClick(0)} className="hover:text-indigo-600 dark:hover:text-indigo-400">All</button>
                           {drilldownPath.map((item, index) => (
                               <div key={index} className="flex items-center">
                                   <Icon name="chevron-right" size={4} className="mx-1" />
                                   <button onClick={() => handleBreadcrumbClick(index + 1)} className="hover:text-indigo-600 dark:hover:text-indigo-400 truncate max-w-[150px]">{item}</button>
                               </div>
                           ))}
                       </div>
                      )}
                </div>
                 <div className="flex items-center gap-2 hide-on-export">
                    {activeTab === 'chart' && (
                        <div className="flex items-center gap-2 w-64">
                             <MultiSelectDropdown 
                               options={allSubgroups}
                               selected={selectedChartSubgroups}
                               onChange={setSelectedChartSubgroups}
                               label="nhóm con"
                            />
                        </div>
                    )}
                    <div className="inline-flex rounded-lg shadow-sm p-1 bg-slate-100/50 dark:bg-slate-900/50">
                        <button onClick={() => setActiveTab('card')} className={`py-1.5 px-4 text-sm font-semibold rounded-md transition-colors ${activeTab === 'card' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-white shadow' : 'text-slate-600 dark:text-slate-300 hover:bg-slate-200/60 dark:hover:bg-slate-700'}`}>Thẻ</button>
                        <button onClick={() => setActiveTab('chart')} className={`py-1.5 px-4 text-sm font-semibold rounded-md transition-colors ${activeTab === 'chart' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-white shadow' : 'text-slate-600 dark:text-slate-300 hover:bg-slate-200/60 dark:hover:bg-slate-700'}`}>Biểu đồ</button>
                    </div>
                    <button onClick={handleExport} disabled={isExporting} title="Xuất Ảnh" className="p-2 text-slate-500 dark:text-slate-400 rounded-md hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors">
                        {isExporting ? <Icon name="loader-2" className="animate-spin" /> : <Icon name="camera" />}
                    </button>
                 </div>
            </div>
            {activeTab === 'card' ? (
                currentView.data.length === 0 ? (
                    <p className="text-slate-500 dark:text-slate-400 text-center py-8">Không có dữ liệu để hiển thị.</p>
                ) : (
                    <div className="grid gap-3 grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 industry-cards-grid">
                        {currentView.data.map(({ name, revenue, quantity, icon, color }) => {
                            const percentage = currentView.totalRevenue > 0 ? (revenue / currentView.totalRevenue * 100) : 0;
                            const isDrillable = drilldownPath.length < 2;
                            return (
                                <div
                                    key={name}
                                    onClick={isDrillable ? () => handleCardClick(name) : undefined}
                                    className={`group relative flex flex-col justify-between p-3 bg-white dark:bg-[#1c1c1e] border border-slate-200 dark:border-white/5 rounded-2xl shadow-[0_2px_8px_rgba(0,0,0,0.04)] hover:shadow-[0_8px_16px_rgba(0,0,0,0.08)] transition-all duration-300 hover:-translate-y-1 ${isDrillable ? 'cursor-pointer active:scale-95' : 'cursor-default'}`}
                                >
                                    {/* Header: Icon & Percent */}
                                    <div className="flex justify-between items-start mb-2">
                                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center bg-${color}-50 text-${color}-600 dark:bg-${color}-500/10 dark:text-${color}-400 transition-colors`}>
                                            <Icon name={icon} size={4.5} />
                                        </div>
                                        <span className="text-[10px] font-bold px-1.5 py-0.5 rounded-md bg-slate-100 dark:bg-white/10 text-slate-500 dark:text-slate-400">
                                            {percentage.toFixed(1)}%
                                        </span>
                                    </div>

                                    {/* Footer: Info */}
                                    <div>
                                        <div className="text-[10px] font-bold uppercase tracking-wider text-slate-400 truncate mb-0.5" title={name}>{name}</div>
                                        <div className="text-base font-bold text-slate-900 dark:text-white tracking-tight leading-none">{formatCurrency(revenue)}</div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )
            ) : (
                <div className="flex flex-col lg:flex-row items-stretch gap-4">
                    <div className="lg:w-[45%]" ref={pieChartRef} style={{ minHeight: '450px' }}></div>
                    <div className="lg:w-[55%]" ref={barChartRef} style={{ minHeight: '450px' }}></div>
                </div>
            )}
        </div>
    );
};

export default IndustryGrid;

import React, { useState, useEffect, useRef } from 'react';
import { formatCurrency, formatQuantity } from '../../utils/dataUtils';
import { Icon } from '../common/Icon';
import { useDashboardContext } from '../../contexts/DashboardContext';
import { saveKpiTargets, getKpiTargets } from '../../services/dbService';

interface KpiCardsProps {
    onUnshippedClick: () => void;
}

// Compact Horizontal Card with Apple Bento Style
// Updates: rounded-2xl (smaller radius), compact padding, refined typography
const KpiCard: React.FC<{
    icon: string;
    iconColor: string;
    title: string;
    onClick?: () => void;
    children: React.ReactNode;
    trendLabel?: string;
    trendValue?: string;
}> = ({ icon, iconColor, title, onClick, children, trendLabel, trendValue }) => {
    const isClickable = !!onClick;

    // Apple-style vivid colors with subtle backgrounds
    const colorMap: Record<string, string> = {
        blue: 'bg-blue-50 text-blue-600 dark:bg-blue-500/10 dark:text-blue-400',
        teal: 'bg-emerald-50 text-emerald-600 dark:bg-emerald-500/10 dark:text-emerald-400',
        pink: 'bg-pink-50 text-pink-600 dark:bg-pink-500/10 dark:text-pink-400',
        red:  'bg-red-50 text-red-600 dark:bg-red-500/10 dark:text-red-400',
    };

    const iconClass = colorMap[iconColor] || colorMap['blue'];

    return (
        <div
            onClick={onClick}
            className={`relative h-full bg-white dark:bg-[#1c1c1e] rounded-2xl p-4 shadow-[0_2px_10px_rgba(0,0,0,0.03)] border border-slate-100 dark:border-white/5 transition-all duration-300 flex items-center justify-between group ${isClickable ? 'cursor-pointer hover:-translate-y-0.5 hover:shadow-md active:scale-95' : ''}`}
        >
            <div className="flex items-center gap-3.5">
                <div className={`w-11 h-11 rounded-xl flex items-center justify-center ${iconClass} shrink-0 transition-transform group-hover:scale-105`}>
                    <Icon name={icon} size={5} />
                </div>
                <div>
                    <h3 className="text-[10px] font-bold uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-0.5">{title}</h3>
                    <div className="flex flex-col">
                        {children}
                    </div>
                </div>
            </div>

            {(trendLabel || trendValue) && (
                <div className="text-right pl-4 border-l border-slate-100 dark:border-white/5 shrink-0 min-w-[70px]">
                    <p className="text-[9px] text-slate-400 font-bold uppercase tracking-wide">{trendLabel}</p>
                    <p className="text-xs font-bold text-slate-600 dark:text-slate-300 mt-0.5 font-mono">{trendValue}</p>
                </div>
            )}
        </div>
    );
};

// Inline Editor Component
const KpiTargetEditor: React.FC<{ 
    value: string; 
    onChange: (val: string) => void; 
    onFinish: () => void; 
    onCancel: () => void;
}> = ({ value, onChange, onFinish, onCancel }) => {
    const inputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (inputRef.current) {
            inputRef.current.focus();
            inputRef.current.select();
        }
    }, []);

    return (
        <div className="flex items-center gap-1" onClick={(e) => e.stopPropagation()}>
            <input
                ref={inputRef}
                type="number"
                min="0"
                max="100"
                value={value}
                onChange={(e) => onChange(e.target.value)}
                onBlur={onFinish}
                onKeyDown={(e) => {
                    if (e.key === 'Enter') onFinish();
                    if (e.key === 'Escape') onCancel();
                    e.stopPropagation(); 
                }}
                className="w-10 px-1 py-0.5 text-center text-xs font-bold text-slate-900 bg-slate-100 rounded focus:ring-2 focus:ring-blue-500 outline-none"
            />
            <span className="text-[10px] font-bold text-slate-500">%</span>
        </div>
    );
};

const KpiCards: React.FC<KpiCardsProps> = ({ onUnshippedClick }) => {
    const { processedData } = useDashboardContext();
    const kpis = processedData?.kpis;
    const [targets, setTargets] = useState({ hieuQua: 40, traGop: 45 });

    const [editingState, setEditingState] = useState<{ field: 'hieuQua' | 'traGop' | null, value: string }>({ field: null, value: '' });

    useEffect(() => {
        getKpiTargets().then(saved => {
            if (saved) {
                setTargets(saved);
            }
        });
    }, []);

    const startEditing = (e: React.MouseEvent, field: 'hieuQua' | 'traGop') => {
        e.preventDefault();
        e.stopPropagation();
        setEditingState({ field, value: (field === 'hieuQua' ? targets.hieuQua : targets.traGop).toString() });
    };

    const handleEditChange = (val: string) => {
        setEditingState(prev => ({ ...prev, value: val }));
    };

    const submitEditing = () => {
        if (!editingState.field) return;
        const newVal = parseFloat(editingState.value);
        if (!isNaN(newVal) && newVal >= 0 && newVal <= 100) {
            const newTargets = { ...targets, [editingState.field]: newVal };
            setTargets(newTargets);
            saveKpiTargets(newTargets).catch(console.error);
        }
        setEditingState({ field: null, value: '' });
    };

    const cancelEditing = () => {
        setEditingState({ field: null, value: '' });
    };

    if (!kpis) {
        return null;
    }

    const hieuQuaValue = kpis.hieuQuaQD * 100;
    const isHieuQuaGood = hieuQuaValue >= targets.hieuQua;
    const isTraGopGood = kpis.traGopPercent >= targets.traGop;

    return (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8 kpi-grid-for-export">

            {/* CARD 1: DOANH THU QUY ĐỔI */}
            <KpiCard 
                icon="wallet-cards" 
                iconColor="blue" 
                title="Doanh Thu QĐ"
                trendLabel="Thực tế"
                trendValue={formatCurrency(kpis.totalRevenue)}
            >
                <div className="text-2xl font-bold text-slate-900 dark:text-white leading-none tracking-tight">
                    {formatCurrency(kpis.doanhThuQD)}
                </div>
            </KpiCard>

            {/* CARD 2: HIỆU QUẢ QUY ĐỔI */}
            <KpiCard 
                icon="trending-up" 
                iconColor="teal" 
                title="Hiệu Quả QĐ"
                onClick={(e) => startEditing(e, 'hieuQua')}
                trendLabel="Mục tiêu"
                trendValue={editingState.field === 'hieuQua' ? '' : `${targets.hieuQua}%`}
            >
                {editingState.field === 'hieuQua' ? (
                    <KpiTargetEditor value={editingState.value} onChange={handleEditChange} onFinish={submitEditing} onCancel={cancelEditing} />
                ) : (
                    <div className={`text-2xl font-bold leading-none tracking-tight ${isHieuQuaGood ? 'text-emerald-600 dark:text-emerald-400' : 'text-amber-500'}`}>
                        {hieuQuaValue.toFixed(1)}%
                    </div>
                )}
            </KpiCard>

            {/* CARD 3: TỶ LỆ TRẢ GÓP */}
            <KpiCard 
                icon="receipt" 
                iconColor="pink" 
                title="Tỷ Lệ Trả Góp"
                onClick={(e) => startEditing(e, 'traGop')}
                trendLabel="Mục tiêu"
                trendValue={editingState.field === 'traGop' ? '' : `${targets.traGop}%`}
            >
                {editingState.field === 'traGop' ? (
                    <KpiTargetEditor value={editingState.value} onChange={handleEditChange} onFinish={submitEditing} onCancel={cancelEditing} />
                ) : (
                    <div className={`text-2xl font-bold leading-none tracking-tight ${isTraGopGood ? 'text-pink-600 dark:text-pink-400' : 'text-amber-500'}`}>
                        {kpis.traGopPercent.toFixed(1)}%
                    </div>
                )}
            </KpiCard>

            {/* CARD 4: DOANH THU CHỜ XUẤT */}
            <KpiCard 
                icon="archive-restore" 
                iconColor="red" 
                title="DT Chờ Xuất" 
                onClick={onUnshippedClick}
                trendLabel="Thực tế"
                trendValue={formatCurrency(kpis.doanhThuThucChoXuat)}
            >
                <div className="text-2xl font-bold text-slate-900 dark:text-white leading-none tracking-tight">
                    {formatCurrency(kpis.doanhThuQDChoXuat)}
                </div>
            </KpiCard>
        </div>
    );
};

export default KpiCards;
